function jsonRpcErrorBody(code: number, message: string) {
  return {
    jsonrpc: "2.0" as const,
    error: {
      code,
      message,
    },
    id: null,
  };
}

export function buildTransportErrorResponse(error: unknown): {
  status: number;
  body: ReturnType<typeof jsonRpcErrorBody>;
} {
  const message = error instanceof Error ? error.message : String(error);
  const expressLikeError = error as {
    status?: number;
    type?: string;
    code?: string;
  };

  if (
    expressLikeError?.type === "entity.parse.failed"
    || /unexpected token|json/i.test(message)
  ) {
    return {
      status: 400,
      body: jsonRpcErrorBody(
        -32700,
        buildTransportFailureText("请求体不是合法 JSON。"),
      ),
    };
  }

  if (expressLikeError?.status === 413 || expressLikeError?.code === "LIMIT_FILE_SIZE") {
    return {
      status: 413,
      body: jsonRpcErrorBody(
        -32603,
        buildTransportFailureText("请求体过大，服务端没有接受这次请求。"),
      ),
    };
  }

  return {
    status: expressLikeError?.status && expressLikeError.status >= 400
      ? expressLikeError.status
      : 500,
    body: jsonRpcErrorBody(-32603, buildTransportFailureText(message)),
  };
}

