function errorResult(text: string): CallToolResult {
  return {
    content: [{ type: "text", text }],
    isError: true,
  };
}

function normalizeToolResult(
  toolName: string,
  result: CallToolResult,
): CallToolResult {
  if (!result.isError) {
    return result;
  }

  const textParts = result.content.flatMap((item) =>
    item.type === "text" ? [item.text.trim()] : []
  ).filter(Boolean);

  if (textParts.length === 0) {
    return errorResult(buildToolFailureText(toolName, ""));
  }

  const merged = textParts.join("\n\n");
  if (merged.startsWith(`工具 \`${toolName}\` 调用失败。`)) {
    return result;
  }

  return errorResult(buildToolFailureText(toolName, merged));
}

export async function formatResult(
  response: Response,
): Promise<CallToolResult> {
  let content: CallToolResult["content"] = [];
  const contentType = response?.headers.get("content-type") ?? "";

  if (!response.ok) {
    if (contentType.startsWith("image/") || contentType.startsWith("audio/")) {
      return errorResult(
        buildHttpErrorText(response, "响应体是二进制内容，无法直接作为文本展示。"),
      );
    }

    const rawText = await response.text();
    const formattedText = formatTextForModel(contentType, rawText);
    return errorResult(buildHttpErrorText(response, formattedText));
  }

  if (contentType.startsWith("image/")) {
    const data = await valueToBase64(await response.arrayBuffer());
    content = data == null
      ? []
      : [{ type: "image", data, mimeType: contentType }];
  } else if (contentType.startsWith("audio/")) {
    const data = await valueToBase64(await response.arrayBuffer());
    content = data == null
      ? []
      : [{ type: "audio", data, mimeType: contentType }];
  } else {
    const rawText = await response.text();
    const formattedText = formatTextForModel(contentType, rawText);
    content = [{ type: "text", text: formattedText || rawText }];
  }

  return { content };
}

export function createRegisterTool(
  logger: ConsoleLogger,
  server: McpServer,
  getSDK: () => UapiMcpCore,
  allowedScopes: Set<MCPScope>,
  allowedTools?: Set<string>,
  dynamic?: boolean,
): [
  <A extends ZodRawShapeCompat | undefined>(tool: ToolDefinition<A>) => void,
  Array<{ name: string; description: string }>,
  Map<string, ToolDefinition<ZodRawShapeCompat | undefined>>,
] {
  const tools: Array<{ name: string; description: string }> = [];
  const toolMap = new Map<
    string,
    ToolDefinition<ZodRawShapeCompat | undefined>
  >();
  const runTool = async (
    tool: ToolDefinition<ZodRawShapeCompat | undefined>,
    execute: () => Promise<CallToolResult>,
  ): Promise<CallToolResult> => {
    try {
      const result = await execute();
      return normalizeToolResult(tool.name, result);
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      return errorResult(buildToolFailureText(tool.name, message));
    }
  };

  const registerTool = <A extends ZodRawShapeCompat | undefined>(
    tool: ToolDefinition<A>,
  ): void => {
    if (allowedTools && !allowedTools.has(tool.name)) {
      return;
    }

    const scopes = tool.scopes ?? [];
    if (allowedScopes.size > 0 && scopes.length === 0) {
      return;
    }

    if (
      allowedScopes.size > 0
      && !scopes.every((s: MCPScope) => allowedScopes.has(s))
    ) {
      return;
    }

    toolMap.set(
      tool.name,
      tool as ToolDefinition<ZodRawShapeCompat | undefined>,
    );

    if (dynamic) {
      logger.debug("Collected tool for dynamic mode", { name: tool.name });
      tools.push({ name: tool.name, description: tool.description });
      return;
    }

    if (tool.args) {
      server.registerTool(
        tool.name,
        {
          description: tool.description,
          inputSchema: tool.args,
          annotations: tool.annotations,
        },
        async (args, ctx) => {
          return runTool(
            tool as ToolDefinition<ZodRawShapeCompat | undefined>,
            async () => tool.tool(getSDK(), args, ctx),
          );
        },
      );
    } else {
      server.registerTool(
        tool.name,
        {
          description: tool.description,
          annotations: tool.annotations,
        },
        async (ctx) => {
          return runTool(
            tool as ToolDefinition<ZodRawShapeCompat | undefined>,
            async () => tool.tool(getSDK(), ctx),
          );
        },
      );
    }

    logger.debug("Registered tool", { name: tool.name });
    tools.push({ name: tool.name, description: tool.description });
  };

  return [registerTool, tools, toolMap];
}

function matchesSearchTerms(
  terms: string[],
  name: string,
  def: ToolDefinition<ZodRawShapeCompat | undefined>,
): boolean {
  if (terms.length === 0) {
    return true;
  }

  const nameLower = name.toLowerCase();
  const descLower = def.description.toLowerCase();
  const scopesLower = def.scopes?.flatMap((s: unknown) => {
    return typeof s === "string" ? [s.toLowerCase()] : [];
  }) || [];

  return terms.some((term) =>
    nameLower.includes(term)
    || descLower.includes(term)
    || scopesLower.some((s) => s.includes(term))
  );
}

export function registerDynamicTools(
  logger: ConsoleLogger,
  server: McpServer,
  getSDK: () => UapiMcpCore,
  toolMap: Map<string, ToolDefinition<ZodRawShapeCompat | undefined>>,
  allowedScopes: Set<MCPScope>,
): void {
  // 1. list_tools
  server.registerTool("list_tools", {
    description:
      "List available tools. The returned descriptions are intentionally shortened to avoid blowing up the model context. Optionally filter by search terms that match against tool name, description, and scopes.",
    inputSchema: {
      search_terms: z.array(z.string()).optional().describe(
        [
          "Filter the list of tools.",
          "Each term is matched case-insensitively as a substring against tool name, description, and scopes.",
          "Multiple terms are combined with a logical OR: a tool is included if ANY term matches ANY field.",
          "If not provided, all tools are returned.",
          "Descriptions in the output are short summaries instead of full upstream documentation.",
        ].join("\n"),
      ),
    },
    annotations: {
      title: "List Tools",
      readOnlyHint: true,
      destructiveHint: false,
      idempotentHint: true,
      openWorldHint: false,
    },
  }, async (args) => {
    const terms = (args.search_terms ?? []).map((t) => t.toLowerCase());

    const tools: Array<
      { name: string; description: string; scopes?: MCPScope[] | undefined }
    > = [];
    for (const [name, def] of toolMap) {
      if (!matchesSearchTerms(terms, name, def)) {
        continue;
      }

      tools.push({
        name: name,
        description: summarizeToolDescription(def.description),
        scopes: def.scopes,
      });
    }
    return {
      content: [{ type: "text", text: JSON.stringify(tools, null, 2) }],
    };
  });
  logger.debug("Registered dynamic meta-tool", { name: "list_tools" });

  // 2. describe_tool
  server.registerTool("describe_tool_input", {
    description:
      "Get the input schema for one or more tools. It is a good idea to call this tool first to understand how to successfully call execute_tool.",
    inputSchema: {
      tool_names: z.array(z.string()).describe(
        "The names of the tools to describe",
      ),
    },
    annotations: {
      title: "Describe Tool",
      readOnlyHint: true,
      destructiveHint: false,
      idempotentHint: true,
      openWorldHint: false,
    },
  }, async (args) => {
    const parts: string[] = [];
    const unknown: string[] = [];

    if (args.tool_names.length === 0) {
      return {
        content: [{
          type: "text",
          text:
            "No tool names provided. Call list_tools first, then pass one or more tool names here.",
        }],
      };
    }

    for (const toolName of args.tool_names) {
      const def = toolMap.get(toolName);
      if (!def) {
        unknown.push(toolName);
        continue;
      }

      let schemaText = `<input_schema tool="${toolName}">\n\n`;
      if (def.args) {
        const jsonSchema = z.toJSONSchema(z.object(def.args), {
          target: "draft-2020-12",
        });
        schemaText += JSON.stringify(jsonSchema, null, 2);
      } else {
        schemaText += "This tool takes no input parameters.";
      }
      schemaText += `\n\n</input_schema>`;
      parts.push(schemaText);
    }

    if (unknown.length > 0) {
      parts.push(`Unknown tools: ${unknown.join(", ")}`);
    }

    return { content: [{ type: "text", text: parts.join("\n\n") }] };
  });
  logger.debug("Registered dynamic meta-tool", { name: "describe_tool" });

  // 3. execute_tool
  server.registerTool("execute_tool", {
    description:
      "Execute a tool by name with the provided input parameters. If executing a given tool for the first time, it is recommended to call describe_tool_input first to understand the expected input schema.",
    inputSchema: {
      tool_name: z.string().describe("The name of the tool to execute"),
      input: z.record(z.string(), z.unknown()).optional().describe(
        "Input parameters for the tool as a JSON object",
      ),
    },
    annotations: {
      title: "Execute Tool",
      readOnlyHint: false,
      destructiveHint: true,
      idempotentHint: false,
      openWorldHint: true,
    },
  }, async (args, ctx) => {
    const def = toolMap.get(args.tool_name);
    if (!def) {
      return errorResult(
        `Unknown tool: ${args.tool_name}\n\nCall list_tools to inspect the available tool names first.`,
      );
    }

    let validatedInput: Record<string, unknown> = {};
    if (def.args) {
      const vres = z.object(def.args).safeParse(args.input ?? {});
      if (vres.success) {
        validatedInput = vres.data;
      } else {
        const issues = z.prettifyError(vres.error);

        return {
          content: [{
            type: "text",
            text:
              `Invalid input for tool ${args.tool_name}:\n<issues>\n${issues}\n</issues>\n\nCall describe_tool_input for this tool if you need the exact input schema.`,
          }],
          isError: true,
        };
      }
    }

    try {
      let result: CallToolResult;
      if (def.args) {
        result = await def.tool(getSDK(), validatedInput, ctx);
      } else {
        result = await def.tool(getSDK(), ctx);
      }

      return normalizeToolResult(args.tool_name, result);
    } catch (error) {
      const message = error instanceof Error ? error.message : String(error);
      return errorResult(buildToolFailureText(args.tool_name, message));
    }
  });
  logger.debug("Registered dynamic meta-tool", { name: "execute_tool" });

  // 4. list_scopes (only when the server has scopes defined)
  if (mcpScopes.length > 0) {
    const scopes = allowedScopes.size > 0
      ? [...allowedScopes].sort()
      : [...mcpScopes];

    server.registerTool("list_scopes", {
      description: [
        "List the scopes available on this server.",
        "Scopes are categories that group related tools together.",
        "They can be used as search terms when filtering the list of tools.",
      ].join("\n"),
      annotations: {
        title: "List Scopes",
        readOnlyHint: true,
        destructiveHint: false,
        idempotentHint: true,
        openWorldHint: false,
      },
    }, async () => {
      const lines = scopes.map((s) => `- ${s}`);
      return { content: [{ type: "text", text: lines.join("\n") }] };
    });
    logger.debug("Registered dynamic meta-tool", { name: "list_scopes" });
  }
}
function resolveHeader<T>(
  headers: Headers,
  headerNames: string | string[],
  schema: z.ZodType<T>,
  cliFlagValue: T | undefined,
  disableStaticAuth: boolean,
): T | undefined {
  const names = Array.isArray(headerNames) ? headerNames : [headerNames];

  for (const headerName of names) {
    const val = headers.get(headerName);
    if (val != null) {
      return schema.parse(val);
    }
  }

  if (disableStaticAuth || typeof cliFlagValue === "undefined") {
    return undefined;
  }

  return schema.parse(cliFlagValue);
}

export function buildSDK(
  headers: Headers,
  cliFlags: MCPServerFlags,
  disableStaticAuth: boolean,
  logger: { level: string },
) {
  const flags = {
    ...cliFlags,
    uapikey: resolveHeader(
      headers,
      ["UapiKey", "uapikey"],
      z.string(),
      cliFlags.uapikey,
      disableStaticAuth,
    ),
    "uapi-admin-bearer-auth": resolveHeader(
      headers,
      ["UapiAdminBearerAuth", "uapi-admin-bearer-auth"],
      z.string(),
      cliFlags["uapi-admin-bearer-auth"],
      disableStaticAuth,
    ),
  };

  return new UapiMcpCore({
    security: {
      UapiAdminBearerAuth: flags["uapi-admin-bearer-auth"],
      UapiKey: flags.uapikey,
    },
    serverURL: flags["server-url"],
    serverIdx: flags["server-index"],
    debugLogger: logger.level === "debug"
      ? {
        log: (...args) => console.log(...args),
        group: (...args) => console.group(...args),
        groupEnd: (...args) => console.groupEnd(...args),
      }
      : undefined,
  });
}
